import { baseApi } from "@app/store";

import type {
  ClaimGuestTestBody,
  GenerateAuthorizedTestBody,
  GeneratedTest,
  GenerateGuestTestBody,
  GuestSubmitResponse,
  SubmitTestAnswersBody,
  SubmitTestAnswersResponse,
  TestAiExplanationResponse,
  TestBreakdownResponse,
} from "../lib/types";

import { unwrapApiResponse } from "@edu-pwa/core";

export const {
  useGenerateGuestTestQuery,
  useGenerateTestQuery,
  useLazyGenerateTestQuery,
  useGetGeneratedTestByIdQuery,
  useSubmitGuestTestAnswersMutation,
  useSubmitTestAnswersMutation,
  useClaimGuestTestMutation,
  useGetTestBreakdownQuery,
  useLazyGetTestBreakdownQuery,
  useGetTestAiExplanationQuery,
  useLazyGetTestAiExplanationQuery,
} = baseApi.injectEndpoints({
  endpoints: builder => ({
    generateGuestTest: builder.query<GeneratedTest, GenerateGuestTestBody>({
      query: body => ({
        url: "/tests/generate-guest",
        method: "POST",
        body,
      }),
      transformResponse: unwrapApiResponse,
      providesTags: ["GuestTest"],
    }),
    generateTest: builder.query<GeneratedTest, GenerateAuthorizedTestBody>({
      query: body => ({
        url: "/tests/generate",
        method: "POST",
        body,
      }),
      transformResponse: unwrapApiResponse,
      providesTags: ["AuthorizedTest"],
    }),
    // Достать ранее сгенерированный тест по id (напр. восстановление после рефреша
    // во время прохождения, чтобы не генерировать заново). Бэк: GET /tests/:id (без правильных ответов).
    getGeneratedTestById: builder.query<GeneratedTest, string>({
      query: id => ({
        url: `/tests/${id}`,
        method: "GET",
      }),
      transformResponse: unwrapApiResponse,
      providesTags: ["GuestTest"],
    }),
    /** Гостевой submit: результат + детальный разбор + темы для повторения сразу (без AI). */
    submitGuestTestAnswers: builder.mutation<GuestSubmitResponse, SubmitTestAnswersBody>({
      query: body => ({
        url: "/tests/submit-guest",
        method: "POST",
        body,
      }),
      transformResponse: unwrapApiResponse,
      invalidatesTags: ["GuestTest"],
    }),
    /** Авторизованный submit: ЛЁГКИЙ ответ (только result + testHistoryId). Разбор/AI — лениво. */
    submitTestAnswers: builder.mutation<SubmitTestAnswersResponse, SubmitTestAnswersBody>({
      query: body => ({
        url: "/tests/submit",
        method: "POST",
        body,
      }),
      transformResponse: unwrapApiResponse,
      invalidatesTags: ["AuthorizedTest", "User"],
    }),
    claimGuestTest: builder.mutation<GuestSubmitResponse, ClaimGuestTestBody>({
      query: body => ({
        url: "/tests/claim-guest",
        method: "POST",
        body,
      }),
      transformResponse: unwrapApiResponse,
      invalidatesTags: ["AuthorizedTest", "User"],
    }),
    /** Детальный разбор прошлого теста по записи истории. */
    getTestBreakdown: builder.query<TestBreakdownResponse, string>({
      query: testHistoryId => ({
        url: `/users/me/tests/${testHistoryId}/breakdown`,
        method: "GET",
      }),
      transformResponse: unwrapApiResponse,
      providesTags: (_r, _e, id) => [{ type: "AuthorizedTest", id }],
    }),
    /** AI-объяснение прошлого теста (ленивая генерация на бэке + кэш). */
    getTestAiExplanation: builder.query<TestAiExplanationResponse, string>({
      query: testHistoryId => ({
        url: `/users/me/tests/${testHistoryId}/ai-explanation`,
        method: "GET",
      }),
      transformResponse: unwrapApiResponse,
      providesTags: (_r, _e, id) => [{ type: "AuthorizedTest", id: `${id}:ai` }],
    }),
  }),
});

