  useGetRoadmapSubjectsQuery,
  useGetPersonalRoadmapQuery,
  useLazyGetPersonalRoadmapQuery,
  useGetRoadmapHomeQuery,
} = baseApi.injectEndpoints({
    endpoints: builder => ({
      getRoadmapSubjects: builder.query<RoadmapSubjectsListData, void>({
        query: () => "/roadmaps/picker-subjects",
        transformResponse: unwrapApiResponse,
        providesTags: [{ type: "Roadmap", id: "SUBJECTS_LIST" }],
