import { useCallback, useEffect } from "react";

import { useAppDispatch } from "@app/store";
import { baseApi } from "@app/store";

import type { GenerateAuthorizedTestBody } from "@entities/test/lib/types";
import { useGenerateTestQuery } from "@entities/test/model";

import type { Dispatch } from "react";

import type { TestFlowAction } from "../types";
import { applyRemoteGuestTestToState } from "../utils/applyRemoteGuestTestToState";
import { computeGenerationStatus } from "../utils/computeGenerationStatus";
import { isGuestTestFlowReady, shouldSkipGenerateGuestTest } from "../utils/guestTestAcquisitionPolicy";

export interface UseAuthorizedTestAcquisitionParams {
  subjectId: string;
  bookId: string;
  nodeId: string;
  generateBody: GenerateAuthorizedTestBody;
  isResumeCompleteWithScore: boolean;
  dispatch: Dispatch<TestFlowAction>;
  testId: string;
  questionCount: number;
}

export function useAuthorizedTestAcquisition(params: UseAuthorizedTestAcquisitionParams) {
  const { subjectId, bookId, nodeId, generateBody, isResumeCompleteWithScore, dispatch, testId, questionCount } =
    params;

  const dispatchApp = useAppDispatch();

  const skipGenerate =
    !subjectId ||
    !bookId ||
    !nodeId ||
    shouldSkipGenerateGuestTest({
      testId,
      questionCount,
      isResumeCompleteWithScore,
    });

  const {
    data: generatedData,
    isFetching: generateFetching,
    isError: generateError,
    isSuccess: generateSuccess,
    refetch: refetchGenerate,
  } = useGenerateTestQuery(generateBody, { skip: skipGenerate });

  const flowReady = isGuestTestFlowReady({ isResumeCompleteWithScore, questionCount });

  useEffect(() => {
    applyRemoteGuestTestToState({
      generatedData,
      testId,
      dispatch,
      roadmapNodeId: nodeId,
    });
  }, [generatedData, testId, dispatch, nodeId]);

  const generationStatus = computeGenerationStatus({
    sessionReadyWithoutNetwork: skipGenerate,
    generateIsError: generateError,
    generateIsSuccess: generateSuccess,
    generateIsFetching: generateFetching,
    hasGeneratedData: Boolean(generatedData),
  });

  const retryGeneration = useCallback(() => {
    dispatchApp(baseApi.util.invalidateTags(["AuthorizedTest"]));
    if (!skipGenerate) {
      void refetchGenerate();
    }
  }, [dispatchApp, refetchGenerate, skipGenerate]);

  return {
    flowReady,
    generationStatus,
    retryGeneration,
  };
}

