import type { MockQuestion } from "./mockQuestions";

export type GeneratedQuestionType =
  | "single_choice"
  | "multiple_choice"
  | "matching_single"
  | "matching_multiple"
  | "short_answer"
  | "text_input";

export interface GeneratedQuestionRelatedContent {
  pages: number[];
}

export interface GeneratedMatchingItem {
  id: string;
  text: string;
}

interface GeneratedQuestionBase {
  questionText: string;
  relatedContent?: GeneratedQuestionRelatedContent;
  correctAnswerHint?: string;
  devPrefillValue?: string;
}

export interface GeneratedChoiceQuestion extends GeneratedQuestionBase {
  questionType: "single_choice" | "multiple_choice";
  options: string[];
}

export interface GeneratedMatchingQuestion extends GeneratedQuestionBase {
  questionType: "matching_single" | "matching_multiple";
  matchingLeft: GeneratedMatchingItem[];
  matchingRight: GeneratedMatchingItem[];
}

export interface GeneratedTextQuestion extends GeneratedQuestionBase {
  questionType: "short_answer" | "text_input";
}

export type GeneratedTestQuestion = GeneratedChoiceQuestion | GeneratedMatchingQuestion | GeneratedTextQuestion;

export interface GeneratedTest {
  _id: string;
  subjectId: string;
  bookId: string;
  questions: GeneratedTestQuestion[];
  createdAt: string;
}

export type TestAnswerKind = "single" | "multiple" | "matching" | "text";

export interface TestQuestionOption {
  value: string;
  label: string;
}

export interface TestMatchingItem {
  id: string;
  text: string;
}

interface TestQuestionPublicBase {
  id: string;
  text: string;
}

export interface TestChoiceQuestionPublic extends TestQuestionPublicBase {
  kind: "single" | "multiple";
  options: TestQuestionOption[];
}

export interface TestMatchingQuestionPublic extends TestQuestionPublicBase {
  kind: "matching";
  multiple: boolean;
  left: TestMatchingItem[];
  right: TestMatchingItem[];
}

export interface TestTextQuestionPublic extends TestQuestionPublicBase {
  kind: "text";
  multiline: boolean;
}

export type TestQuestionPublic = TestChoiceQuestionPublic | TestMatchingQuestionPublic | TestTextQuestionPublic;

export function cloneTestQuestion(question: TestQuestionPublic): TestQuestionPublic {
  switch (question.kind) {
    case "single":
    case "multiple":
      return { ...question, options: question.options.map(o => ({ ...o })) };
    case "matching":
      return {
        ...question,
        left: question.left.map(i => ({ ...i })),
        right: question.right.map(i => ({ ...i })),
      };
    case "text":
      return { ...question };
  }
}

export interface GuestTrialSubmitResultErrorLine {
  questionId: string;
  questionText: string;
  options: string[];
  selectedOption: string;
  correctOption: string;
  explanation: string;
  topics?: string[];
}

export interface RoadmapTestResultStats {
  correctAnswers: number;
  totalQuestions: number;
  scorePercent: number;
  pointsDelta?: number | null;
}

export interface GuestTrialSubmitResultSnapshot {
  score: string;
  guestPromoAiLead: string;
  errorAnalysis: GuestTrialSubmitResultErrorLine[];
  showErrorBreakdown: boolean;
  resultStats?: RoadmapTestResultStats;
  topicsToRevisit?: string[];
  /** Авторизованный submit: id записи истории для ленивой дозагрузки разбора. */
  testHistoryId?: string;
}

export interface PersistedTest {
  version: number;
  subjectId: string;
  bookId: string;
  testId: string;
  roadmapNodeId: string;
  roadmapSessionId: string;
  questions: TestQuestionPublic[];
  answers: Record<string, string>;
  currentIndex: number;
  completed: boolean;
  finalScore?: string;
  submitResultSnapshot?: GuestTrialSubmitResultSnapshot;
}

export interface SubmitTestAnswersResult {
  totalQuestions: number;
  correctAnswers: number;
  scorePercent: number;
}

export interface SubmitTestAnswersMistake {
  question: string;
  explanation: string;
  whereToRead?: {
    bookTitle: string;
    chapterTitle: string;
    pages: number[];
    topicTitle?: string;
  };
}

/** Детальный разбор одного вопроса (из breakdown или guest-submit). */
export interface TestBreakdownAnswer {
  questionType?: string;
  questionText: string;
  options: string[];
  correctOption: string;
  selectedOption: string;
  isCorrect: boolean;
  explanation: string;
  relatedContent?: { pages?: number[]; topicId?: string; topicTitle?: string };
}

/** Тема для повторения (агрегат ошибок по теме). */
export interface TopicToReview {
  topicId: string;
  topicTitle: string;
  totalCount: number;
  wrongCount: number;
  scorePercent: number;
}

/**
 * Лёгкий ответ авторизованного submit (`POST /tests/submit`): только результат + id.
 * Разбор и AI тянутся лениво по `testHistoryId`.
 */
export interface SubmitTestAnswersResponse {
  testHistoryId: string;
  testId: string;
  result: SubmitTestAnswersResult;
  trialTopicMastery?: unknown;
  roadmap?: unknown;
}

/** Ответ гостевого submit и claim (`/tests/submit-guest`, `/tests/claim-guest`) — разбор сразу, без AI. */
export interface GuestSubmitResponse {
  testHistoryId?: string;
  testId: string;
  result: SubmitTestAnswersResult;
  detailedAnswers: TestBreakdownAnswer[];
  topicsToReview: TopicToReview[];
  trialTopicMastery?: unknown;
}

/** Ответ `GET /users/me/tests/:id/breakdown`. */
export interface TestBreakdownResponse {
  testHistoryId?: string;
  result?: SubmitTestAnswersResult;
  detailedAnswers: TestBreakdownAnswer[];
  topicsToReview: TopicToReview[];
}

/** Ответ `GET /users/me/tests/:id/ai-explanation` (IAIFeedback). */
export interface TestAiExplanationResponse {
  summary: string;
  mistakes: SubmitTestAnswersMistake[];
}

export function formatSubmitTestResultScoreLabel(result: SubmitTestAnswersResult): string {
  return `${result.correctAnswers}/${result.totalQuestions}`;
}

function mapChoiceOptions(options: unknown): TestQuestionOption[] {
  return Array.isArray(options)
    ? options.filter((o): o is string => typeof o === "string").map(opt => ({ value: opt, label: opt }))
    : [];
}

function mapMatchingItems(items: unknown): TestMatchingItem[] {
  return Array.isArray(items)
    ? items
        .filter((i): i is GeneratedMatchingItem => i != null && typeof i === "object")
        .map(i => ({ id: String(i.id), text: String(i.text) }))
    : [];
}

function mapGeneratedQuestion(question: GeneratedTestQuestion, index: number): TestQuestionPublic {
  const id = `q-${index}`;
  const text = question.questionText ?? "";

  switch (question.questionType) {
    case "single_choice":
      return { id, text, kind: "single", options: mapChoiceOptions(question.options) };
    case "multiple_choice":
      return { id, text, kind: "multiple", options: mapChoiceOptions(question.options) };
    case "matching_single":
    case "matching_multiple":
      return {
        id,
        text,
        kind: "matching",
        multiple: question.questionType === "matching_multiple",
        left: mapMatchingItems(question.matchingLeft),
        right: mapMatchingItems(question.matchingRight),
      };
    case "short_answer":
      return { id, text, kind: "text", multiline: false };
    case "text_input":
      return { id, text, kind: "text", multiline: true };
    default:
      // Неизвестный тип — деградируем до однострочного текстового ввода.
      return { id, text, kind: "text", multiline: false };
  }
}

export function mapGeneratedTestToClient(data: GeneratedTest): { testId: string; questions: TestQuestionPublic[] } {
  const rows = Array.isArray(data.questions) ? data.questions : [];
  return {
    testId: data._id,
    questions: rows.map(mapGeneratedQuestion),
  };
}

export function toPublicQuestions(questions: readonly MockQuestion[]): TestQuestionPublic[] {
  return questions.map(q => ({
    id: q.id,
    text: q.text,
    kind: "single",
    options: q.options.map(o => ({ value: o.value, label: o.label })),
  }));
}

export const PERSISTED_TEST_VERSION = 9;
export const TEST_STORAGE_KEY_PREFIX = "edu-test-";

export interface GenerateGuestTestBody {
  fullBook: boolean;
  subjectId: string;
  bookId: string;
  chapterId?: string;
}

export interface GenerateAuthorizedTestBody {
  subjectId: string;
  bookId: string;
  /** Roadmap-узел для теста по уроку. Не передаётся для kahoot. */
  nodeId?: string;
  /** Если true — `chapterId` игнорируется, тест по всей книге. */
  fullBook?: boolean;
  /** Конкретная глава (когда `fullBook=false`). */
  chapterId?: string;
  testProfile?: string;
  /** Только roadmap-flow задаёт явное количество; в kahoot бэк решает сам. */
  questionCount?: number;
}

export interface SubmitTestAnswerItem {
  questionText: string;
  selectedOption: string;
}

export interface SubmitTestAnswersBody {
  testId: string;
  answers: SubmitTestAnswerItem[];
  roadmapNodeId?: string;
  roadmapSessionId?: string;
}

/** @deprecated Используйте SubmitTestAnswersBody. */
export type SubmitTestAnswersRequest = SubmitTestAnswersBody;

export function buildSubmitTestAnswersBody(
  testId: string,
  questions: readonly TestQuestionPublic[],
  answers: Record<string, string>,
  roadmapNodeId: string,
  roadmapSessionId: string,
): SubmitTestAnswersBody {
  return {
    testId,
    ...(roadmapNodeId !== "" ? { roadmapNodeId } : {}),
    ...(roadmapSessionId !== "" ? { roadmapSessionId } : {}),
    answers: questions.map(q => ({
      questionText: q.text,
      selectedOption: answers[q.id] ?? "",
    })),
  };
}

export interface ClaimGuestTestBody extends SubmitTestAnswersBody {
  forTrial: boolean;
}

export function buildClaimGuestTestBody(test: PersistedTest): ClaimGuestTestBody {
  return {
    ...buildSubmitTestAnswersBody(test.testId, test.questions, test.answers, test.roadmapNodeId, test.roadmapSessionId),
    forTrial: true,
  };
}

