import { type FC, useCallback, useMemo, useState } from "react";

import { ROUTES } from "@app/router/config/paths";

import { RoadmapSubjectPickerWidget } from "@widgets/roadmap/ui/RoadmapSubjectPickerWidget";
import { RoadmapTimelineWidget } from "@widgets/roadmap/ui/RoadmapTimelineWidget";

import { LESSON_TITLE_QUERY_KEY } from "@features/lesson/lib/constants";
import { ROADMAP_SUBJECT_QUERY_KEY } from "@features/roadmapSubject/lib/constants";
import { useRoadmapSubjectSearchParams } from "@features/roadmapSubject/lib/useRoadmapSubjectSearchParams";

import type { PersonalRoadmapNode, RoadmapSubjectListItem } from "@entities/roadmap/lib/types";
import { useGetPersonalRoadmapQuery, useGetRoadmapSubjectsQuery } from "@entities/roadmap/model";
import { RoadmapNodeLessonDrawer } from "@entities/roadmap/ui/RoadmapNodeLessonDrawer";

import { SplitButton } from "@shared/components";
import { useTransitionNavigate } from "@shared/hooks";

import { Box, Typography } from "@mui/material";

const EMPTY_SUBJECTS: RoadmapSubjectListItem[] = [];

export const RoadmapScreenWidget: FC = () => {
  const [pickerOpen, setPickerOpen] = useState(false);
  const [lessonPreviewNode, setLessonPreviewNode] = useState<PersonalRoadmapNode | null>(null);
  const navigate = useTransitionNavigate();

  const { data: subjectsData, isLoading: subjectsLoading } = useGetRoadmapSubjectsQuery();
  const items = useMemo(() => subjectsData?.subjects ?? EMPTY_SUBJECTS, [subjectsData?.subjects]);

  const { subjectId, subjectTitle, setSubjectId } = useRoadmapSubjectSearchParams(items);

  const {
    data: personal,
    isFetching: personalLoading,
    error: personalError,
  } = useGetPersonalRoadmapQuery({ subjectId: subjectId ?? "" }, { skip: subjectId == null });

  const roadmapNotConfigured =
    personalError != null && "status" in personalError && personalError.status === 404;

  const handleNodePress = useCallback((node: PersonalRoadmapNode) => {
    setLessonPreviewNode(node);
  }, []);

  const handleCloseLessonPreview = useCallback(() => setLessonPreviewNode(null), []);

  const handleConfirmLesson = useCallback(() => {
    if (lessonPreviewNode == null || subjectId == null) return;
    const qs = new URLSearchParams();
    qs.set(LESSON_TITLE_QUERY_KEY, lessonPreviewNode.title);
    navigate(`${ROUTES.LESSON(subjectId, lessonPreviewNode.bookId, lessonPreviewNode.nodeId)}?${qs.toString()}`);
    setLessonPreviewNode(null);
  }, [lessonPreviewNode, subjectId, navigate]);

  const handleConfirmTest = useCallback(() => {
    if (lessonPreviewNode == null || subjectId == null) return;
    navigate(`${ROUTES.TEST(lessonPreviewNode.nodeId)}?${ROADMAP_SUBJECT_QUERY_KEY}=${encodeURIComponent(subjectId)}`);
    setLessonPreviewNode(null);
  }, [lessonPreviewNode, subjectId, navigate]);

  return (
    <>
      <Box
        sx={{
          position: "sticky",
          top: 0,
          zIndex: 2,
          flexShrink: 0,
          px: 1.5,
          pt: 1.5,
          pb: 2,
        }}
      >
        <SplitButton
          disabled={subjectsLoading}
          label={subjectsLoading ? "Загрузка…" : subjectTitle}
          trailingButtonAriaLabel="Открыть выбор предмета"
          onClick={() => setPickerOpen(true)}
        />
      </Box>

      {personalLoading && (
        <Typography color="text.secondary" variant="body2" sx={{ px: 1.5 }}>
          Загрузка персонального роадмапа…
        </Typography>
      )}

      {!personalLoading && subjectId != null && roadmapNotConfigured && (
        <Typography color="text.secondary" variant="body2" sx={{ px: 1.5 }}>
          Карта знаний для этого предмета ещё не настроена. Обратитесь к администратору.
        </Typography>
      )}

      {personal != null && personal.nodes.length > 0 && (
        <RoadmapTimelineWidget
          nodes={personal.nodes}
          nextRecommendedNodeId={personal.nextRecommended?.nodeId ?? null}
          scrollToLastAvailableKey={`${personal.subjectId}:${personal.version}`}
          onNodePress={handleNodePress}
        />
      )}

      <RoadmapNodeLessonDrawer
        open={lessonPreviewNode != null}
        node={lessonPreviewNode}
        onClose={handleCloseLessonPreview}
        onConfirmToLesson={handleConfirmLesson}
        onConfirmToTest={handleConfirmTest}
      />

      <RoadmapSubjectPickerWidget
        open={pickerOpen}
        onOpen={() => setPickerOpen(true)}
        onClose={() => setPickerOpen(false)}
        subjects={items}
        selectedSubjectId={subjectId}
        onSelectSubject={setSubjectId}
      />
    </>
  );
};

