import { resolveRoadmapNodeDescription } from "@entities/roadmap/lib/resolveRoadmapNodeDescription";
import type { PersonalRoadmapNode } from "@entities/roadmap/lib/types";

import { BaseButton, SwipeableDrawer } from "@shared/components";

import type { FC } from "react";

import ArrowBackIcon from "@mui/icons-material/ArrowBack";
import { Box, IconButton, Typography } from "@mui/material";

export interface RoadmapNodeLessonDrawerProps {
  open: boolean;
  node: PersonalRoadmapNode | null;
  onClose: () => void;
  onConfirmToLesson: () => void;
  onConfirmToTest: () => void;
}

export const RoadmapNodeLessonDrawer: FC<RoadmapNodeLessonDrawerProps> = ({
  open,
  node,
  onClose,
  onConfirmToLesson,
  onConfirmToTest,
}) => {
  const effectiveOpen = open && node != null;
  const body = node != null ? resolveRoadmapNodeDescription(node) : "";

  return (
    <SwipeableDrawer
      withPuller
      open={effectiveOpen}
      onClose={onClose}
      appBarOptions={{
        title: node?.title ?? "Урок",
        startAdornment: (
          <IconButton
            edge="start"
            aria-label="Закрыть"
            sx={{ mr: 1, color: t => t.palette.m3.onSurface }}
            onClick={onClose}
          >
            <ArrowBackIcon />
          </IconButton>
        ),
      }}
      PaperProps={{
        sx: {
          background: t => t.palette.m3.surfaceContainer,
        },
      }}
    >
      {node != null && (
        <Box
          sx={{
            display: "flex",
            flexDirection: "column",
            gap: 2,
            px: 2,
            pb: 3,
            pt: 1,
            flex: 1,
            overflow: "auto",
          }}
        >
          <Typography variant="body1" color="text.secondary" sx={{ lineHeight: 1.5 }}>
            {body}
          </Typography>
          <BaseButton fullWidth variant="contained" onClick={onConfirmToLesson}>
            Перейти к уроку
          </BaseButton>

          {node?.knowledgeMapTestBlocked && (
            <BaseButton fullWidth variant="text" onClick={onConfirmToTest}>
              Перейти к тесту
            </BaseButton>
          )}
        </Box>
      )}
    </SwipeableDrawer>
  );
};

