import { useCallback, useMemo } from "react";
import { type BlockerFunction, useBlocker, useParams } from "react-router-dom";

import { flexColumnFill, mergeLayoutSx, scrollableArea } from "@app/layouts/lib/mobileShellSx";
import { useAppBarMeta } from "@app/layouts/lib/useAppBarMeta";
import { ROUTES } from "@app/router/config/paths";

import { RoadmapTestExitConfirmDialog } from "@widgets/test/ui/RoadmapTestExitConfirmDialog";
import { RoadmapTestResultSheet } from "@widgets/test/ui/RoadmapTestResultSheet/RoadmapTestResultSheet";
import { TestQuestionWidget } from "@widgets/test/ui/TestQuestionWidget";

import { useAuthorizedTestSession } from "@features/test/lib/hooks/useAuthorizedTestSession";
import { TestGenerationStatus } from "@features/test/lib/static";

import { useTransitionNavigate } from "@shared/hooks";

import { Box, Typography } from "@mui/material";

const RoadmapTestReady = ({ subjectId, bookId, nodeId }: { subjectId: string; bookId: string; nodeId: string }) => {
  const navigate = useTransitionNavigate();
  const { title } = useAppBarMeta();
  const session = useAuthorizedTestSession({
    subjectId,
    bookId,
    roadmapNodeId: nodeId,
    subjectTitle: title,
  });
  const { dismissResultSheet, tryAgain } = session;

  const shouldBlockExit = useMemo(
    () => !session.completed && session.generationStatus === TestGenerationStatus.Ready && session.questions.length > 0,
    [session.completed, session.generationStatus, session.questions.length],
  );

  const exitBlockerFn = useCallback<BlockerFunction>(
    ({ currentLocation, nextLocation }) =>
      currentLocation.pathname !== nextLocation.pathname ||
      currentLocation.search !== nextLocation.search ||
      currentLocation.hash !== nextLocation.hash,
    [],
  );

  const blocker = useBlocker(shouldBlockExit ? exitBlockerFn : false);

  const handleCancelExit = useCallback(() => {
    blocker.reset?.();
  }, [blocker]);

  const handleConfirmExitFromTest = useCallback(() => {
    tryAgain();
    blocker.proceed?.();
  }, [tryAgain, blocker]);

  const handleLeaveAfterResult = useCallback(() => {
    dismissResultSheet();
    navigate(ROUTES.ROADMAP, { replace: true });
  }, [dismissResultSheet, navigate]);

  const handleOpenLesson = useCallback(() => {
    dismissResultSheet();
    navigate(ROUTES.LESSON(subjectId, bookId, nodeId));
  }, [dismissResultSheet, navigate, subjectId, bookId, nodeId]);

  return (
    <>
      <TestQuestionWidget session={session} />
      <RoadmapTestResultSheet
        open={session.showResultSheet}
        snapshot={session.submitResultSnapshot}
        subjectTitle={session.subjectTitle}
        onClose={handleLeaveAfterResult}
        onTryAgain={session.tryAgain}
        onOpenLesson={handleOpenLesson}
      />
      <RoadmapTestExitConfirmDialog
        open={blocker.state === "blocked"}
        onCancel={handleCancelExit}
        onConfirmExit={handleConfirmExitFromTest}
      />
    </>
  );
};

export function RoadmapTestPage() {
  const { subjectId, bookId, nodeId } = useParams<{
    subjectId: string;
    bookId: string;
    nodeId: string;
  }>();

  if (!subjectId || !bookId || !nodeId) {
    return (
      <Box sx={mergeLayoutSx(flexColumnFill, scrollableArea, { width: "100%", p: 2 })}>
        <Typography color="text.secondary">
          Не указаны предмет, книга или узел урока. Откройте тест с экрана урока.
        </Typography>
      </Box>
    );
  }

  return (
    <Box sx={mergeLayoutSx(flexColumnFill, scrollableArea, { width: "100%" })}>
      <RoadmapTestReady subjectId={subjectId} bookId={bookId} nodeId={nodeId} />
    </Box>
  );
}

