import { useCallback, useEffect, useMemo, useReducer, useRef, useState } from "react";

import type { PersistedTest } from "@entities/test/lib/types";
import { cloneTestQuestion, PERSISTED_TEST_VERSION } from "@entities/test/lib/types";
import { usePersistedTest } from "@entities/test/lib/usePersistedTest";

import type { TestFlowState } from "../types";
import { selectResumeSnapshot } from "../utils/selectResumeSnapshot";
import { createInitialTestFlowState, testFlowReducer } from "../utils/testFlowState";

import type { UseAuthorizedTestSessionOptions } from "./types";
import { useAuthorizedTestAcquisition } from "./useAuthorizedTestAcquisition";
import { useAuthorizedTestSubmit } from "./useAuthorizedTestSubmit";
import { useFlushTestProgress } from "./useFlushTestProgress";
import { useTestTaking } from "./useTestTaking";

export function useAuthorizedTestSession(options: UseAuthorizedTestSessionOptions) {
  const { subjectId, bookId, roadmapNodeId, subjectTitle } = options;

  const { restoredState, save, clear } = usePersistedTest(subjectId, bookId, roadmapNodeId);

  const resumeSnapshot = useMemo(() => selectResumeSnapshot(restoredState), [restoredState]);

  const [state, dispatch] = useReducer(testFlowReducer, resumeSnapshot, createInitialTestFlowState);

  const [resultSheetDismissed, setResultSheetDismissed] = useState(false);

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    if (!state.completed) setResultSheetDismissed(() => false);
  }, [state.completed]);

  const generateBody = useMemo(
    () => ({
      subjectId,
      bookId,
      nodeId: roadmapNodeId,
      fullBook: false,
      testProfile: "regular",
      questionCount: 10,
    }),
    [subjectId, bookId, roadmapNodeId],
  );

  const { flowReady, generationStatus, retryGeneration } = useAuthorizedTestAcquisition({
    subjectId,
    bookId,
    nodeId: roadmapNodeId,
    generateBody,
    isResumeCompleteWithScore: Boolean(state.completed && state.finalScore),
    dispatch,
    testId: state.testId,
    questionCount: state.questions.length,
  });

  const getPayload = useCallback((): PersistedTest | null => {
    if (!subjectId || state.testId === "") return null;
    if (state.questions.length === 0 && !(state.completed && state.finalScore)) return null;
    return {
      version: PERSISTED_TEST_VERSION,
      subjectId,
      bookId,
      testId: state.testId,
      roadmapNodeId: state.roadmapNodeId,
      roadmapSessionId: state.roadmapSessionId,
      questions: state.questions.map(cloneTestQuestion),
      answers: state.answers,
      currentIndex: state.currentIndex,
      completed: state.completed,
      ...(state.completed && state.finalScore ? { finalScore: state.finalScore } : {}),
      ...(state.submitResultSnapshot
        ? {
            submitResultSnapshot: {
              ...state.submitResultSnapshot,
              errorAnalysis: state.submitResultSnapshot.errorAnalysis.map(e => ({ ...e })),
            },
          }
        : {}),
    };
  }, [
    subjectId,
    bookId,
    state.testId,
    state.roadmapNodeId,
    state.roadmapSessionId,
    state.questions,
    state.answers,
    state.currentIndex,
    state.completed,
    state.finalScore,
    state.submitResultSnapshot,
  ]);

  const canPersistProgress =
    state.testId !== "" &&
    (flowReady || state.questions.length > 0 || Object.keys(state.answers).length > 0 || state.completed);

  useFlushTestProgress({
    enabled: canPersistProgress,
    save,
    getPayload,
  });

  const getFlowState = useCallback((): TestFlowState => state, [state]);

  const { finishTest, submitting, submitError, retrySubmit, tryAgain } = useAuthorizedTestSubmit({
    clearPersist: clear,
    dispatch,
    getFlowState,
  });

  const taking = useTestTaking(state, dispatch);
  const takingRef = useRef(taking);

  useEffect(() => {
    takingRef.current = taking;
  }, [taking]);

  const handleNext = useCallback(() => {
    const { hasAnswerOnCurrent, isLastQuestion, handleNext: goNext } = takingRef.current;

    if (!hasAnswerOnCurrent) return;

    if (isLastQuestion) return finishTest();

    return goNext();
  }, [finishTest]);

  const showResultSheet = Boolean(state.completed && state.submitResultSnapshot && !resultSheetDismissed);

  const dismissResultSheet = useCallback(() => setResultSheetDismissed(true), []);

  return {
    generationStatus,
    questions: state.questions,
    currentQuestion: taking.currentQuestion,
    currentIndex: state.currentIndex,
    answers: state.answers,
    canGoNext: taking.canGoNext,
    canGoPrev: taking.canGoPrev,
    hasAnswerOnCurrent: taking.hasAnswerOnCurrent,
    isLastQuestion: taking.isLastQuestion,
    completed: state.completed,
    submitResultSnapshot: state.submitResultSnapshot,
    showResultSheet,
    dismissResultSheet,
    tryAgain,
    handleAnswerChange: taking.handleAnswerChange,
    handleNext,
    handlePrev: taking.handlePrev,
    retryGeneration,
    submitting,
    submitError,
    retrySubmit,
    subjectTitle,
    subjectId,
    bookId,
    nodeId: roadmapNodeId,
  };
}

export type AuthorizedTestSession = ReturnType<typeof useAuthorizedTestSession>;

