import type { PersistedTest, TestQuestionPublic } from "@entities/test/lib/types";
import { cloneTestQuestion, mapGeneratedTestToClient } from "@entities/test/lib/types";

import type { TestFlowAction, TestFlowState } from "../../types";

function sameQuestionShape(a: readonly TestQuestionPublic[], b: readonly TestQuestionPublic[]): boolean {
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i += 1) {
    if (a[i]?.id !== b[i]?.id) return false;
  }
  return true;
}

function snapshotFromResume(
  resume: PersistedTest,
): TestFlowState["submitResultSnapshot"] {
  if (!resume.submitResultSnapshot) return null;
  return {
    ...resume.submitResultSnapshot,
    errorAnalysis: resume.submitResultSnapshot.errorAnalysis.map(e => ({ ...e })),
  };
}

export function createInitialTestFlowState(resume: PersistedTest | null): TestFlowState {
  if (!resume) {
    return {
      questions: [],
      testId: "",
      answers: {},
      currentIndex: 0,
      completed: false,
      finalScore: undefined,
      submitResultSnapshot: null,
      roadmapNodeId: "",
      roadmapSessionId: "",
    };
  }
  return {
    questions: resume.questions.map(cloneTestQuestion),
    testId: resume.testId,
    answers: { ...resume.answers },
    currentIndex: resume.currentIndex,
    completed: Boolean(resume.completed),
    finalScore: resume.finalScore,
    submitResultSnapshot: snapshotFromResume(resume),
    roadmapNodeId: resume.roadmapNodeId,
    roadmapSessionId: resume.roadmapSessionId,
  };
}

export function testFlowReducer(state: TestFlowState, action: TestFlowAction): TestFlowState {
  switch (action.type) {
    case "tryAgainReset":
      return {
        questions: [],
        testId: "",
        answers: {},
        currentIndex: 0,
        completed: false,
        finalScore: undefined,
        submitResultSnapshot: null,
        roadmapNodeId: "",
        roadmapSessionId: "",
      };
    case "applyGeneration": {
      const { testId, questions } = mapGeneratedTestToClient(action.test);
      if (state.testId === testId && sameQuestionShape(state.questions, questions)) {
        return state;
      }
      return {
        ...state,
        questions,
        testId,
        answers: {},
        currentIndex: 0,
        completed: false,
        finalScore: undefined,
        submitResultSnapshot: null,
        roadmapNodeId: action.roadmapNodeId ?? "",
        roadmapSessionId: action.roadmapSessionId ?? "",
      };
    }
    case "answer":
      return {
        ...state,
        answers: { ...state.answers, [action.questionId]: action.value },
      };
    case "goPrev":
      return { ...state, currentIndex: Math.max(0, state.currentIndex - 1) };
    case "incrementIndex":
      return { ...state, currentIndex: state.currentIndex + 1 };
    case "submitSuccess":
      return {
        ...state,
        completed: true,
        finalScore: action.snapshot.score,
        submitResultSnapshot: action.snapshot,
      };
    default:
      return state;
  }
}

