import { useCallback, useState } from "react";

import { useAppDispatch } from "@app/store";
import { baseApi } from "@app/store";

import { buildSubmitTestAnswersBody } from "@entities/test/lib/types";
import { useSubmitTestAnswersMutation } from "@entities/test/model";

import type { Dispatch } from "react";

import type { TestFlowAction, TestFlowState } from "../types";
import { canSubmitGuestTrialFlow, mapAuthorizedSubmitToSnapshot } from "../utils/guestTrialSubmit";

export interface UseAuthorizedTestSubmitParams {
  clearPersist: () => void;
  dispatch: Dispatch<TestFlowAction>;
  getFlowState: () => TestFlowState;
}

export function useAuthorizedTestSubmit(params: UseAuthorizedTestSubmitParams) {
  const { clearPersist, dispatch, getFlowState } = params;

  const dispatchApp = useAppDispatch();
  const [submitTestAnswers] = useSubmitTestAnswersMutation();
  const [submitError, setSubmitError] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  const tryAgain = useCallback(() => {
    clearPersist();
    dispatch({ type: "tryAgainReset" });
    dispatchApp(baseApi.util.invalidateTags(["AuthorizedTest"]));
  }, [clearPersist, dispatch, dispatchApp]);

  const finishTest = useCallback(async () => {
    const flow = getFlowState();
    if (!canSubmitGuestTrialFlow(flow)) return;

    const { testId, questions, answers, roadmapNodeId: rNode, roadmapSessionId: rSession } = flow;

    setSubmitError(false);
    setSubmitting(true);
    try {
      const body = buildSubmitTestAnswersBody(testId, questions, answers, rNode, rSession);
      const response = await submitTestAnswers(body).unwrap();
      dispatch({
        type: "submitSuccess",
        snapshot: mapAuthorizedSubmitToSnapshot(response),
      });
    } catch {
      setSubmitError(true);
    } finally {
      setSubmitting(false);
    }
  }, [dispatch, getFlowState, submitTestAnswers]);

  return {
    finishTest,
    submitting,
    submitError,
    retrySubmit: finishTest,
    tryAgain,
  };
}

