import type { GeneratedTest } from "@entities/test/lib/types";

import type { Dispatch } from "react";

import type { TestFlowAction } from "../../types";

export function applyRemoteGuestTestToState(params: {
  generatedData: GeneratedTest | undefined;
  testId: string;
  dispatch: Dispatch<TestFlowAction>;
  roadmapNodeId?: string;
  roadmapSessionId?: string;
}): void {
  const { generatedData, testId, dispatch, roadmapNodeId, roadmapSessionId } = params;
  if (testId === "" && generatedData) {
    dispatch({
      type: "applyGeneration",
      test: generatedData,
      ...(roadmapNodeId != null && roadmapNodeId !== "" ? { roadmapNodeId } : {}),
      ...(roadmapSessionId != null && roadmapSessionId !== "" ? { roadmapSessionId } : {}),
    });
  }
}

